import tensorflow as tf
from flask import Flask, request, jsonify
import pandas as pd
import numpy as np
from sklearn.preprocessing import LabelEncoder
from sklearn.model_selection import train_test_split
import os
import uuid
from werkzeug.utils import secure_filename
import cv2
from PIL import Image
import io

app = Flask(__name__)
app.config['UPLOAD_FOLDER'] = 'uploads'
app.config['MAX_CONTENT_LENGTH'] = 16 * 1024 * 1024

# Create upload directory
os.makedirs(app.config['UPLOAD_FOLDER'], exist_ok=True)

# Global model and data structures
model = None
label_encoder = LabelEncoder()
class_names = []
data_buffer = []

def create_model(num_classes):
    model = tf.keras.Sequential([
        tf.keras.layers.Conv2D(32, (3, 3), activation='relu', input_shape=(224, 224, 3)),
        tf.keras.layers.MaxPooling2D((2, 2)),
        tf.keras.layers.Conv2D(64, (3, 3), activation='relu'),
        tf.keras.layers.MaxPooling2D((2, 2)),
        tf.keras.layers.Conv2D(64, (3, 3), activation='relu'),
        tf.keras.layers.Flatten(),
        tf.keras.layers.Dense(64, activation='relu'),
        tf.keras.layers.Dense(num_classes, activation='softmax')
    ])
    
    model.compile(optimizer='adam',
                  loss='sparse_categorical_crossentropy',
                  metrics=['accuracy'])
    return model

def preprocess_image(image_path):
    image = cv2.imread(image_path)
    image = cv2.resize(image, (224, 224))
    image = image.astype('float32') / 255.0
    return image

def load_csv_data(file_path):
    df = pd.read_csv(file_path)
    return df

def train_model():
    global model, label_encoder, class_names
    
    if len(data_buffer) < 1:
        return False
    
    # Prepare data
    images = []
    labels = []
    
    for item in data_buffer:
        image_path = item['image_path']
        label = item['label']
        
        try:
            image = preprocess_image(image_path)
            images.append(image)
            labels.append(label)
        except Exception as e:
            print(f"Error processing image {image_path}: {e}")
            continue
    
    if len(images) < 1:
        return False
    
    images = np.array(images)
    labels = np.array(labels)
    
    # Encode labels
    encoded_labels = label_encoder.fit_transform(labels)
    class_names = label_encoder.classes_
    
    # Create and train model
    num_classes = len(np.unique(encoded_labels))
    model = create_model(num_classes)
    
    # Split data
    X_train, X_test, y_train, y_test = train_test_split(
        images, encoded_labels, test_size=0.2, random_state=42
    )
    
    # Train model
    model.fit(X_train, y_train, epochs=5, validation_data=(X_test, y_test))
    
    return True

@app.route('/upload', methods=['POST'])
def upload_file():
    if 'file' not in request.files:
        return jsonify({'error': 'No file provided'}), 400
    
    file = request.files['file']
    if file.filename == '':
        return jsonify({'error': 'No file selected'}), 400
    
    if file and file.filename.endswith('.csv'):
        filename = secure_filename(file.filename)
        file_path = os.path.join(app.config['UPLOAD_FOLDER'], filename)
        file.save(file_path)
        
        try:
            df = load_csv_data(file_path)
            # Process CSV data
            for index, row in df.iterrows():
                if 'image_path' in row and 'label' in row:
                    data_buffer.append({
                        'image_path': row['image_path'],
                        'label': row['label']
                    })
            
            # Retrain model with new data
            train_model()
            
            return jsonify({'message': 'Data uploaded and model retrained successfully'})
        except Exception as e:
            return jsonify({'error': str(e)}), 500
    
    elif file and file.filename.endswith(('.jpg', '.jpeg', '.png')):
        filename = secure_filename(file.filename)
        file_path = os.path.join(app.config['UPLOAD_FOLDER'], filename)
        file.save(file_path)
        
        # Get label from form data
        label = request.form.get('label')
        if label:
            data_buffer.append({
                'image_path': file_path,
                'label': label
            })
            
            # Retrain model with new data
            train_model()
            
            return jsonify({'message': 'Image uploaded and model retrained successfully'})
        else:
            return jsonify({'error': 'Label required'}), 400
    
    return jsonify({'error': 'Invalid file type'}), 400

@app.route('/predict', methods=['POST'])
def predict():
    if model is None:
        return jsonify({'error': 'Model not trained yet'}), 400
    
    if 'image' not in request.files:
        return jsonify({'error': 'No image provided'}), 400
    
    file = request.files['image']
    if file.filename == '':
        return jsonify({'error': 'No image selected'}), 400
    
    try:
        image = Image.open(io.BytesIO(file.read()))
        image = image.convert('RGB')
        image = image.resize((224, 224))
        image_array = np.array(image)
        image_array = image_array.astype('float32') / 255.0
        image_array = np.expand_dims(image_array, axis=0)
        
        predictions = model.predict(image_array)
        predicted_class = np.argmax(predictions[0])
        confidence = predictions[0][predicted_class]
        
        predicted_label = label_encoder.inverse_transform([predicted_class])[0]
        
        return jsonify({
            'prediction': predicted_label,
            'confidence': float(confidence),
            'all_predictions': {
                label: float(prob) for label, prob in zip(class_names, predictions[0])
            }
        })
    except Exception as e:
        return jsonify({'error': str(e)}), 500

@app.route('/status', methods=['GET'])
def status():
    return jsonify({
        'model_trained': model is not None,
        'training_examples': len(data_buffer),
        'classes': class_names.tolist() if class_names.size > 0 else []
    })

if __name__ == '__main__':
    app.run(debug=True, host='0.0.0.0', port=5000)